INSERT INTO purchase_alerts (
  conversation_id, phone_number, customer_name, product_id,
  product_name_snapshot, price_snapshot, currency_snapshot, notes, status
)
VALUES (
  NULLIF($1, '')::uuid, $2, NULLIF($3, ''), $4,
  $5, $6, COALESCE(NULLIF($7, ''), 'PYG'), $8, 'pending'
)
RETURNING id AS alert_id, created_at;

